    [Fact]
    public async Task Given_FewerValidProposedFollowUps_ThanBudget_When_EvaluateAsync_Invoked_Then_It_Should_Fill_ToFive_Using_DeterministicSupplementalCandidates()
    {
        // Arrange
        await using var connection = new SqliteConnection("Data Source=:memory:");
        await connection.OpenAsync();

        var options = new DbContextOptionsBuilder<PresaleDataDbContext>()
            .UseSqlite(connection)
            .Options;

        await using var dbContext = new PresaleDataDbContext(options);
        await dbContext.Database.EnsureCreatedAsync();

        var lead = new PresaleLead
        {
            Id = Guid.NewGuid(),
            SessionId = "phase4-0",
            CurrentPhase = ConversationPhase.Discovery,
            CurrentDiscoveryRound = 0,
            FollowUpAskedCount = 0,
            PendingDiscoveryItemsJson = "[\"timeline\",\"budget\"]"
        };

        dbContext.PresaleLeads.Add(lead);
        await dbContext.SaveChangesAsync();

        var repository = new PresaleLeadRepository(dbContext);
        var initialTimeline = await repository.AddAskedQuestionAsync(lead.Id, new AskedQuestion
        {
            QuestionText = "What timeline are you targeting?",
            Phase = "Discovery",
            AgentName = "discovery_agent",
            QuestionKind = DiscoveryQuestionKind.Initial,
            RoundNumber = 0,
            QuestionTopicKey = "timeline"
        });

        var initialBudget = await repository.AddAskedQuestionAsync(lead.Id, new AskedQuestion
        {
            QuestionText = "What budget range do you have?",
            Phase = "Discovery",
            AgentName = "discovery_agent",
            QuestionKind = DiscoveryQuestionKind.Initial,
            RoundNumber = 0,
            QuestionTopicKey = "budget"
        });

        var sut = new DiscoveryFollowUpPolicyService(repository);

        // Act
        var result = await sut.EvaluateAsync(new EvaluateFollowUpPolicyRequest(
            LeadId: lead.Id,
            ProposedQuestions:
            [
                new ProposedFollowUpQuestion("Any hard deadline?", "timeline", initialTimeline!.Id, true),
                new ProposedFollowUpQuestion("Any budget constraints?", "budget", initialBudget!.Id, true)
            ]));

        // Assert
        result.Success.ShouldBeTrue();
        result.AllowFollowUpQuestions.ShouldBeTrue();
        result.ApprovedQuestions.Count.ShouldBe(5);
        result.ApprovedQuestions.All(x => x.RoundNumber == 1).ShouldBeTrue();
        result.ApprovedQuestions.Count(x => x.QuestionTopicKey == "timeline").ShouldBe(1);
        result.ApprovedQuestions.Count(x => x.QuestionTopicKey == "budget").ShouldBe(1);
        result.ApprovedQuestions.Select(x => x.QuestionTopicKey).Distinct().Count().ShouldBe(5);
        result.ApprovedQuestions.Count(x => x.QuestionTopicKey is not "timeline" and not "budget").ShouldBe(3);
    }

