            ProposedQuestions:
            [
                new ProposedFollowUpQuestion("Timeline details?", "timeline", initialTimeline!.Id, true)
            ]));

        var updatedLead = await repository.GetPresaleLeadAsync(lead.Id);

        // Assert
        result.Success.ShouldBeTrue();
        result.AllowFollowUpQuestions.ShouldBeFalse();
