        result.ApprovedQuestions.Count.ShouldBe(0);

        updatedLead.ShouldNotBeNull();
        updatedLead.DiscoveryCompletenessReason.ShouldNotBeNull();
        updatedLead.DiscoveryCompletenessReason.ShouldContain("unknowns_required");
    }

